-- MoH PMS Legacy Source Tables (extracted from npm_dashboard)
-- Tables: ihrisdata, kpi, kpi_job_category
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
-- MySQL 8+ rejects zero dates in strict mode; legacy export used 0000-00-00 for unknown DOB.
SET SESSION sql_mode = 'ALLOW_INVALID_DATES,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION';

-- Table: ihrisdata
CREATE TABLE `ihrisdata` (
  `id` int NOT NULL,
  `ihris_pid` varchar(200) NOT NULL,
  `district_id` varchar(100) DEFAULT NULL,
  `district` varchar(100) DEFAULT NULL,
  `dhis_facility_id` varchar(100) DEFAULT NULL,
  `dhis_district_id` varchar(100) DEFAULT NULL,
  `nin` varchar(100) DEFAULT NULL,
  `card_number` varchar(100) DEFAULT NULL,
  `ipps` varchar(100) DEFAULT NULL,
  `facility_type_id` varchar(100) DEFAULT NULL,
  `facility_id` varchar(100) DEFAULT NULL,
  `facility` varchar(100) DEFAULT NULL,
  `department_id` varchar(255) DEFAULT NULL,
  `department` varchar(100) DEFAULT NULL,
  `division` varchar(255) DEFAULT NULL,
  `section` varchar(100) NOT NULL,
  `unit` varchar(200) DEFAULT NULL,
  `job_id` varchar(100) DEFAULT NULL,
  `job` varchar(100) DEFAULT NULL,
  `employment_terms` varchar(100) DEFAULT NULL,
  `salary_grade` varchar(10) DEFAULT NULL,
  `surname` varchar(100) DEFAULT NULL,
  `firstname` varchar(100) DEFAULT NULL,
  `othername` varchar(100) DEFAULT NULL,
  `mobile` varchar(100) DEFAULT NULL,
  `telephone` varchar(100) DEFAULT NULL,
  `institution_type_id` varchar(100) DEFAULT NULL,
  `institutiontype_name` varchar(100) NOT NULL,
  `last_update` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `gender` varchar(30) DEFAULT NULL,
  `birth_date` date DEFAULT NULL,
  `cadre` varchar(100) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `region` varchar(100) NOT NULL,
  `supervisor_id` varchar(100) NOT NULL,
  `supervisor_id_2` varchar(100) NOT NULL,
  `kpi_group_id` varchar(100) NOT NULL,
  `data_role` int NOT NULL DEFAULT '0',
  `is_active` int NOT NULL DEFAULT '1'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
-- Table: kpi
CREATE TABLE `kpi` (
  `id` int NOT NULL,
  `kpi_id` varchar(100) NOT NULL,
  `short_name` text,
  `indicator_statement` text NOT NULL,
  `description` text,
  `computation` text,
  `numerator` varchar(100) NOT NULL,
  `denominator` varchar(100) NOT NULL,
  `data_sources` text NOT NULL,
  `frequency` varchar(200) NOT NULL,
  `computation_category` varchar(100) NOT NULL DEFAULT 'Ratio',
  `subject_area` int DEFAULT NULL,
  `category_two_id` int DEFAULT NULL COMMENT 'Object if CPHL',
  `indicator_type_id` int DEFAULT NULL,
  `current_target` int DEFAULT NULL,
  `is_cumulative` int DEFAULT '0',
  `gauge_type` varchar(100) NOT NULL DEFAULT 'ascending_scale',
  `job_id` varchar(100) NOT NULL,
  `status` int NOT NULL DEFAULT '1'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
-- Table: kpi_job_category
CREATE TABLE `kpi_job_category` (
  `id` int NOT NULL,
  `job_id` varchar(100) NOT NULL,
  `job` varchar(100) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
SET FOREIGN_KEY_CHECKS=1;
